    fn tokenToSymbol(self: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 51,
            .@"string_sq" => 53,
            .@"string_dq" => 54,
            .@"indent" => 58,
            .@"outdent" => 59,
            .@"integer" => 113,
            .@"real" => 114,
            .@"true" => 115,
            .@"false" => 116,
            .@"assign" => 65,
            .@"colon" => 70,
            .@"comma" => 71,
            .@"not_sym" => 75,
            .@"question" => 76,
            .@"star" => 77,
            .@"lbracket" => 78,
            .@"rbracket" => 79,
            .@"bar" => 82,
            .@"minus" => 104,
            .@"dot" => 106,
            .@"lparen" => 109,
            .@"rparen" => 110,
            .@"at" => 120,
            .@"lbrace" => 121,
            .@"rbrace" => 124,
            .@"lt" => 143,
            .@"gt" => 144,
            .@"plus" => 148,
            .@"slash" => 149,
            .@"percent" => 150,
            .@"arrow" => 74,
            .@"fat_arrow" => 89,
            .@"nullish" => 90,
            .@"plus_assign" => 99,
            .@"minus_assign" => 100,
            .@"star_assign" => 101,
            .@"slash_assign" => 102,
            .@"const_assign" => 103,
            .@"pipe" => 138,
            .@"or_sym" => 139,
            .@"and_sym" => 140,
            .@"eq" => 141,
            .@"ne" => 142,
            .@"le" => 145,
            .@"ge" => 146,
            .@"dotdot" => 147,
            .@"power" => 151,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *Parser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return SYM_IDENT;
        if (self.try_ident_as_keyword(token, text)) |sym| return sym;
        return SYM_IDENT;
    }

    fn try_ident_as_keyword(self: *Parser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.state_stack.getLast();
        if (rip.keyword_as(text)) |id| {
            const id_idx = @intFromEnum(id);
            const sym = keyword_to_symbol[id_idx];
            if (sym != 0 and getAction(state, sym) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return sym;
            }
            const fallback = keyword_fallback_symbol;
            if (fallback != 0 and getAction(state, fallback) != 0) {
                self.last_matched_id = @intCast(id_idx);
                return fallback;
            }
        }
        return null;
    }

    pub fn parseProgram(self: *Parser) !Sexp {
        self.injected_token = SYM_program_START;
        return self.doParse(SYM_program);
    }
    pub fn parseExpr(self: *Parser) !Sexp {
        self.injected_token = SYM_expr_START;
        return self.doParse(SYM_expr);
    }
};

// Symbol IDs
const SYM_program: u16 = 3;
const SYM_program_START: u16 = 126;
const SYM_expr: u16 = 4;
const SYM_expr_START: u16 = 128;
const SYM_IDENT: u16 = 61;

// Mapping from rip.keyword_id to grammar symbol IDs (computed at comptime)
const keyword_to_symbol = blk: {
    var arr: [512]u16 = .{0} ** 512;
    if (@hasField(rip.keyword_id, "NEWLINE")) arr[@intFromEnum(rip.keyword_id.NEWLINE)] = 51;
    if (@hasField(rip.keyword_id, "ZIG")) arr[@intFromEnum(rip.keyword_id.ZIG)] = 52;
    if (@hasField(rip.keyword_id, "STRING_SQ")) arr[@intFromEnum(rip.keyword_id.STRING_SQ)] = 53;
    if (@hasField(rip.keyword_id, "STRING_DQ")) arr[@intFromEnum(rip.keyword_id.STRING_DQ)] = 54;
    if (@hasField(rip.keyword_id, "PUB")) arr[@intFromEnum(rip.keyword_id.PUB)] = 55;
    if (@hasField(rip.keyword_id, "EXTERN")) arr[@intFromEnum(rip.keyword_id.EXTERN)] = 56;
    if (@hasField(rip.keyword_id, "EXPORT")) arr[@intFromEnum(rip.keyword_id.EXPORT)] = 57;
    if (@hasField(rip.keyword_id, "INDENT")) arr[@intFromEnum(rip.keyword_id.INDENT)] = 58;
    if (@hasField(rip.keyword_id, "OUTDENT")) arr[@intFromEnum(rip.keyword_id.OUTDENT)] = 59;
    if (@hasField(rip.keyword_id, "FUN")) arr[@intFromEnum(rip.keyword_id.FUN)] = 60;
    if (@hasField(rip.keyword_id, "IDENT")) arr[@intFromEnum(rip.keyword_id.IDENT)] = 61;
    if (@hasField(rip.keyword_id, "SUB")) arr[@intFromEnum(rip.keyword_id.SUB)] = 62;
    if (@hasField(rip.keyword_id, "USE")) arr[@intFromEnum(rip.keyword_id.USE)] = 63;
    if (@hasField(rip.keyword_id, "TYPE")) arr[@intFromEnum(rip.keyword_id.TYPE)] = 64;
